const FantasmaCard = ({ fantasma, evidencias }) => {
  return (
    <>
      <tr>
        <td>{fantasma.nombre}</td>
        {evidencias.map((evidencia, index) => (
          <td key={index}>{evidencia.prueba}</td>
        ))}
      </tr>
    </>
  );
};

export default FantasmaCard;
